const QUALITY_WEIGHT = { unique: 40, rare: 20, magic: 5, normal: 1 }
const equippedItems = Object.values(equipped).filter(Boolean)
const pool = equippedItems.flatMap(item => Array(QUALITY_WEIGHT[item.quality] ?? 1).fill(item))
const sacrificed = pool[Math.floor(rng() * pool.length)]

inventoryStore.setState((s) => {
  const newEquipped = { ...s.equipped }
  if (equipSlot) delete newEquipped[equipSlot]
  const emptyBag = createInventory()
  return { equipped: newEquipped, bag: emptyBag, magicFind: calcMF(newEquipped, emptyBag) }
})

const entry: GraveyardEntry = {
  item:    { ...sacrificed, identified: true },
  floor, tier, level,
  lostAt:  new Date().toISOString(),
  classId, killedBy,
}

invokeGhostEcho: (entryIndex) => {
  const { graveyard, ghostCharm } = get()
  if (ghostCharm) return   // already active — one echo at a time
  const entry = graveyard[graveyard.length - 1 - entryIndex]  // sorted reversed
  if (!entry) return
  set({ ghostCharm: entry.item })
},

// Shows once when graveyard has items and no echo is active
useEffect(() => {
  if (hasSeenGhostEchoHint || ghostCharm || graveyard.length === 0) return
  const t1 = setTimeout(() => setGhostEchoHint(true), 2000)
  const t2 = setTimeout(() => {
    setGhostEchoHint(false)
    markGhostEchoHintSeen()
  }, 6000)
  return () => { clearTimeout(t1); clearTimeout(t2) }
}, [])
